"use client";

import { useState } from "react";
import { searchStocks } from "@/lib/api";
import type { StockSearchResult } from "@/types";
import Link from "next/link";
import { Search } from "lucide-react";

export default function StockSearchPage() {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState<StockSearchResult[]>([]);
  const [loading, setLoading] = useState(false);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;
    setLoading(true);
    try {
      const data = await searchStocks(query);
      setResults(data.results);
    } catch {
      setResults([]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">종목 검색</h1>

      <form onSubmit={handleSearch} className="relative">
        <Search className="absolute left-4 top-3.5 w-5 h-5 text-gray-400" />
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="종목명 또는 코드를 입력하세요 (예: 삼성전자, 005930)"
          className="w-full pl-12 pr-4 py-3 bg-white/5 border border-white/10 rounded-xl focus:outline-none focus:ring-2 focus:ring-skyblue text-white placeholder-gray-500"
        />
      </form>

      {loading && <p className="text-center text-gray-400 text-sm">검색 중...</p>}

      {results.length > 0 && (
        <div className="space-y-2">
          {results.map((s) => (
            <Link
              key={s.code}
              href={`/stock/${s.code}`}
              className="block bg-white/5 border border-white/10 rounded-xl p-4 hover:bg-white/10 transition-colors"
            >
              <div className="flex justify-between items-center">
                <div>
                  <p className="font-medium">{s.name}</p>
                  <p className="text-xs text-gray-400">{s.code}</p>
                </div>
                <span className="text-xs px-2 py-1 rounded-full bg-white/10 text-gray-300">
                  {s.market}
                </span>
              </div>
            </Link>
          ))}
        </div>
      )}

      {!loading && query && results.length === 0 && (
        <p className="text-center text-gray-400 text-sm">검색 결과가 없습니다.</p>
      )}
    </div>
  );
}
